DO $$ DECLARE r RECORD; v_count INT := 0; BEGIN FOR r IN SELECT p.proname, pg_get_function_identity_arguments(p.oid) as args FROM pg_proc p JOIN pg_namespace n ON p.pronamespace = n.oid WHERE n.nspname = 'public' AND p.prokind = 'f' AND (p.proconfig IS NULL OR NOT 'search_path=public' = ANY(p.proconfig)) LOOP BEGIN EXECUTE format('ALTER FUNCTION public.%I(%s) SET search_path = public', r.proname, r.args); v_count := v_count + 1; EXCEPTION WHEN OTHERS THEN RAISE NOTICE 'Skip: % - %', r.proname, SQLERRM; END; END LOOP; RAISE NOTICE 'Fixed % functions', v_count; END $$;;
